"Has IPSD and Major Depression Diagnosis" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "IPSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Major Depression (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Major Depression (qicore-condition-encounter-diagnosis)") AS MajorDepression WHERE MajorDepression.patient_id = p.patient_id AND j1.resource IS NOT NULL AND CAST((SELECT sub.resource FROM "IPSD" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP) - INTERVAL '60 day' <= CAST(intervalStart(CASE WHEN fhirpath_text(MajorDepression.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MajorDepression.resource, 'onsetDateTime'), fhirpath_text(MajorDepression.resource, 'onsetPeriod.start'), fhirpath_text(MajorDepression.resource, 'recordedDate')), fhirpath_text(MajorDepression.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MajorDepression.resource, 'onsetDateTime'), fhirpath_text(MajorDepression.resource, 'onsetPeriod.start'), fhirpath_text(MajorDepression.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MajorDepression.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MajorDepression.resource, 'onsetDateTime'), fhirpath_text(MajorDepression.resource, 'onsetPeriod.start'), fhirpath_text(MajorDepression.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MajorDepression.resource, 'onsetDateTime'), fhirpath_text(MajorDepression.resource, 'onsetPeriod.start'), fhirpath_text(MajorDepression.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(MajorDepression.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MajorDepression.resource, 'onsetDateTime'), fhirpath_text(MajorDepression.resource, 'onsetPeriod.start'), fhirpath_text(MajorDepression.resource, 'recordedDate')), fhirpath_text(MajorDepression.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MajorDepression.resource, 'onsetDateTime'), fhirpath_text(MajorDepression.resource, 'onsetPeriod.start'), fhirpath_text(MajorDepression.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MajorDepression.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MajorDepression.resource, 'onsetDateTime'), fhirpath_text(MajorDepression.resource, 'onsetPeriod.start'), fhirpath_text(MajorDepression.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MajorDepression.resource, 'onsetDateTime'), fhirpath_text(MajorDepression.resource, 'onsetPeriod.start'), fhirpath_text(MajorDepression.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS TIMESTAMP) <= CAST((SELECT sub.resource FROM "IPSD" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP) + INTERVAL '60 day')
),
"Numerator 1" AS (
SELECT * FROM "Cumulative Medication Duration Greater Than or Equal to 84 Days"
),
"Numerator 2" AS (
SELECT * FROM "Cumulative Medication Duration Greater Than or Equal to 180 Days"
),
"Qualifying Encounters" AS (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Preventive Care Services Established Office Visit, 18 and Up" UNION SELECT patient_id, resource FROM "Encounter: Preventive Care Services Initial Office Visit, 18 and Up" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Annual Wellness Visit" UNION SELECT patient_id, resource FROM "Encounter: Nursing Facility Visit" UNION SELECT patient_id, resource FROM "Encounter: Psych Visit Diagnostic Evaluation" UNION SELECT patient_id, resource FROM "Encounter: Psych Visit Psychotherapy" UNION SELECT patient_id, resource FROM "Encounter: Telephone Visits" UNION SELECT patient_id, resource FROM "Encounter: Virtual Encounter") AS _union WHERE fhirpath_text(resource, 'status') IN ('finished')) AS ValidEncounter WHERE CAST((SELECT sub.resource FROM "IPSD" AS sub WHERE sub.patient_id = ValidEncounter.patient_id LIMIT 1) AS TIMESTAMP) - INTERVAL '60 day' <= CAST(intervalStart(CASE WHEN fhirpath_text(ValidEncounter.resource, 'period') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ValidEncounter.resource, 'period')), '{') THEN fhirpath_text(ValidEncounter.resource, 'period') ELSE intervalFromBounds(fhirpath_text(ValidEncounter.resource, 'period'), fhirpath_text(ValidEncounter.resource, 'period'), TRUE, TRUE) END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(ValidEncounter.resource, 'period') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ValidEncounter.resource, 'period')), '{') THEN fhirpath_text(ValidEncounter.resource, 'period') ELSE intervalFromBounds(fhirpath_text(ValidEncounter.resource, 'period'), fhirpath_text(ValidEncounter.resource, 'period'), TRUE, TRUE) END) AS TIMESTAMP) <= CAST((SELECT sub.resource FROM "IPSD" AS sub WHERE sub.patient_id = ValidEncounter.patient_id LIMIT 1) AS TIMESTAMP) + INTERVAL '60 day'
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST((SELECT sub.resource FROM "IPSD" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS DATE)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST((SELECT sub.resource FROM "IPSD" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS DATE)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST((SELECT sub.resource FROM "IPSD" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS DATE)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST((SELECT sub.resource FROM "IPSD" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS DATE)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 18 AND EXISTS (SELECT 1 FROM "Has IPSD and Major Depression Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Qualifying Encounters" AS sub WHERE sub.patient_id = p.patient_id)
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Numerator 1".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Numerator 1", (SELECT CASE WHEN "Numerator 2".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Numerator 2" FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator 1" ON p.patient_id = "Numerator 1".patient_id LEFT JOIN "Numerator 2" ON p.patient_id = "Numerator 2".patient_id ORDER BY p.patient_id ASC
